// ============================================================
// FUNÇÃO DE PESQUISA
// ============================================================

/**
 * Normaliza texto removendo acentos para comparação.
 * Ex: "Frango à zambeziana" → "frango a zambeziana"
 */
function normalizarTexto(texto) {
  return texto
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9\s-]/g, '')
    .trim();
}

/**
 * Pesquisa alimentos na base de dados local.
 *
 * @param {string} query - Texto de pesquisa (parcial, sem acentos OK)
 * @param {Object} [opcoes] - Filtros opcionais
 * @param {string} [opcoes.categoria] - Filtrar por categoria (ex: 'proteina')
 * @param {string[]} [opcoes.tags] - Filtrar por tags (ex: ['halal', 'sem_gluten']) — AND lógico
 * @param {string} [opcoes.origem] - Filtrar por origem (ex: 'mocambicana')
 * @param {string} [opcoes.subcategoria] - Filtrar por subcategoria (ex: 'peixe')
 * @param {number} [opcoes.limite=20] - Número máximo de resultados
 * @returns {Array} Resultados ordenados por relevância
 */
export function pesquisarAlimentosLocal(query, opcoes = {}) {
  const { categoria, tags, origem, subcategoria, limite = 20 } = opcoes;

  // Se não há query, retorna lista filtrada
  let resultados = ALIMENTOS_DB;

  // Aplicar filtros
  if (categoria) {
    resultados = resultados.filter(a => a.categoria === categoria);
  }
  if (subcategoria) {
    resultados = resultados.filter(a => a.subcategoria === subcategoria);
  }
  if (origem) {
    resultados = resultados.filter(a => a.origem === origem);
  }
  if (tags && tags.length > 0) {
    resultados = resultados.filter(a =>
      tags.every(tag => a.tags.includes(tag))
    );
  }

  // Se não há query de texto, retorna filtrados (com limite)
  if (!query || query.trim() === '') {
    return resultados.slice(0, limite);
  }

  const queryNorm = normalizarTexto(query);
  if (queryNorm === '') return resultados.slice(0, limite);

  // Palavras da query para matching parcial
  const palavras = queryNorm.split(/\s+/).filter(Boolean);

  // Classificar resultados por relevância
  const comScore = resultados.map(alimento => {
    const nomeNorm = normalizarTexto(alimento.nome);

    let score = 0;

    // Match exacto do nome completo → máxima relevância
    if (nomeNorm === queryNorm) {
      score = 100;
    }
    // Nome começa com a query
    else if (nomeNorm.startsWith(queryNorm)) {
      score = 80;
    }
    // Alguma palavra do nome começa com a query
    else if (nomeNorm.split(/\s+/).some(p => p.startsWith(queryNorm))) {
      score = 60;
    }
    // Nome contém a query
    else if (nomeNorm.includes(queryNorm)) {
      score = 40;
    }
    // Todas as palavras da query aparecem no nome
    else if (palavras.length > 1 && palavras.every(p => nomeNorm.includes(p))) {
      score = 30;
    }
    // Pelo menos uma palavra da query aparece no nome
    else if (palavras.some(p => nomeNorm.includes(p))) {
      score = 10;
    }
    // Nenhum match
    else {
      score = 0;
    }

    return { ...alimento, _score: score };
  });

  // Filtrar sem match e ordenar por score (desc), depois nome (asc)
  return comScore
    .filter(a => a._score > 0)
    .sort((a, b) => {
      if (b._score !== a._score) return b._score - a._score;
      return a.nome.localeCompare(b.nome, 'pt');
    })
    .slice(0, limite)
    .map(({ _score, ...alimento }) => alimento);
}
